109	// ── Codex discovery from upstream ────────────────────────────────────
110	
111	export interface DiscoveredCodexFixture {
112	  codexName: string;
113	  bareLocalPath: string;
114	  baseSha: string;
115	}
116	
117	/**
118	 * Walk upstream yields and find every entry that looks like a
119	 * codex-fixture's setup yield (has `codexName`, `bareLocalPath`,
120	 * `baseSha`). Same duck-typing pattern other engines use.
121	 */
122	export function discoverCodexFixtures(
123	  upstream: Record<string, unknown>,
124	): DiscoveredCodexFixture[] {
125	  const result: DiscoveredCodexFixture[] = [];
126	  for (const value of Object.values(upstream)) {
127	    if (
128	      typeof value === 'object' &&
129	      value !== null &&
130	      !Array.isArray(value)
131	    ) {
132	      const obj = value as Record<string, unknown>;
133	      if (
134	        typeof obj.codexName === 'string' &&
135	        typeof obj.bareLocalPath === 'string' &&
136	        typeof obj.baseSha === 'string'
137	      ) {
138	        result.push({
139	          codexName: obj.codexName,
140	          bareLocalPath: obj.bareLocalPath,
141	          baseSha: obj.baseSha,
142	        });
143	      }
144	    }
145	  }
146	  return result;
147	}
148	
149	function selectCodex(
150	  upstream: Record<string, unknown>,
151	  explicitName: string | undefined,
152	): DiscoveredCodexFixture {
153	  const candidates = discoverCodexFixtures(upstream);
154	  if (candidates.length === 0) {
155	    throw new Error(
156	      `[${DESIGN_ID}] no codex fixture found in context.upstream — expected at least one ` +
157	        `upstream yield with {codexName, bareLocalPath, baseSha} (the codex-fixture's yield shape).`,
158	    );
159	  }
160	  if (explicitName !== undefined) {
161	    const match = candidates.find((c) => c.codexName === explicitName);
162	    if (!match) {
163	      throw new Error(
164	        `[${DESIGN_ID}] givens.codexName="${explicitName}" did not match any upstream codex ` +
165	          `(seen: ${candidates.map((c) => c.codexName).join(', ')}).`,
166	      );
167	    }
168	    return match;
169	  }
170	  if (candidates.length > 1) {
171	    throw new Error(
172	      `[${DESIGN_ID}] multiple codex fixtures found in context.upstream ` +
173	        `(${candidates.map((c) => c.codexName).join(', ')}); set givens.codexName to disambiguate.`,
174	    );
175	  }
176	  return candidates[0]!;
177	}
178	
179	// ── Git helpers ──────────────────────────────────────────────────────
180	
181	async function git(
182	  args: string[],
183	  cwd: string,
184	  maxBufferBytes: number,
185	): Promise<string> {
186	  try {
187	    const { stdout } = await execFile('git', args, { cwd, maxBuffer: maxBufferBytes });
188	    return stdout;
189	  } catch (err: unknown) {
190	    const e = err as { stderr?: string; message?: string };
191	    throw new Error(`git ${args[0]} failed: ${e.stderr || e.message || 'unknown error'}`);
192	  }
193	}
194	
195	interface CommitMeta {
196	  sha: string;
197	  message: string;
198	  filesChanged: number;
199	  insertions: number;
200	  deletions: number;
201	}
202	
203	/**
204	 * Resolve the head SHA from the bare repo's `main` ref. The codex-
205	 * fixture pushes the base SHA there at setup; the test guild's seal
206	 * flow updates `main` as work commits land.
207	 */
208	async function resolveHeadSha(barePath: string): Promise<string> {
209	  const out = (await git(['rev-parse', 'main'], barePath, 1 * 1024 * 1024)).trim();
210	  if (!/^[0-9a-f]{40}$/i.test(out)) {
211	    throw new Error(`[${DESIGN_ID}] unexpected git rev-parse output: "${out.slice(0, 80)}"`);
212	  }
213	  return out;
214	}
215	
216	/**
217	 * Enumerate commits in `<base>..<head>` ancestry order (oldest → newest).
218	 * Returns just the SHAs.
219	 */
220	async function listCommitShas(barePath: string, base: string, head: string): Promise<string[]> {
221	  if (base === head) return [];
222	  const out = await git(
223	    ['rev-list', '--reverse', `${base}..${head}`],
224	    barePath,
225	    10 * 1024 * 1024,
226	  );
227	  return out
228	    .split('\n')
229	    .map((s) => s.trim())
230	    .filter((s) => s.length > 0);
231	}
232	
233	async function readCommitMessage(barePath: string, sha: string): Promise<string> {
234	  // %B = full message (subject + body, no trailing newline).
235	  const out = await git(
236	    ['show', '--no-patch', '--format=%B', sha],
237	    barePath,
238	    5 * 1024 * 1024,
239	  );
